  export async function seedTechniciansIfEmpty(): Promise<void> {
    const result = await db.execute<{ count: string }>(
      sql`SELECT COUNT(*)::text AS count FROM technicians`
    );
    const count = result.rows[0]?.count ?? "0";

    if (parseInt(count, 10) < 10) {
      console.log(`[seed] Seeding ${SEED_DATA.length} technicians...`);
      const chunks: typeof SEED_DATA[] = [];
      for (let i = 0; i < SEED_DATA.length; i += 50) chunks.push(SEED_DATA.slice(i, i + 50));
      for (const chunk of chunks) {
        await db.insert(techniciansTable).values(
          chunk.map(r => ({
            fullName: r.fullName,
            avatarUrl: r.avatarUrl ?? undefined,
            specialty: r.specialty ?? undefined,
            serviceArea: r.serviceArea ?? undefined,
            bio: r.bio ?? undefined,
            hourlyRate: r.hourlyRate,
            googlePlaceId: r.googlePlaceId ?? undefined,
            phone: r.phone ?? undefined,
            website: r.website ?? undefined,
            latitude: r.latitude ?? undefined,
            longitude: r.longitude ?? undefined,
          }))
        ).onConflictDoNothing();
      }
      console.log(`[seed] Done.`);
    }

    // Patch any records in production that are missing phone or website
    const missing = await db
      .select({ id: techniciansTable.id, googlePlaceId: techniciansTable.googlePlaceId })
      .from(techniciansTable)
      .where(or(isNull(techniciansTable.phone), isNull(techniciansTable.website)));

    if (missing.length > 0) {
      console.log(`[seed] Patching ${missing.length} records missing phone/website...`);
      const seedMap = new Map(SEED_DATA.map(r => [r.googlePlaceId, r]));
      for (const row of missing) {
        if (!row.googlePlaceId) continue;
        const seedRow = seedMap.get(row.googlePlaceId);
        if (!seedRow) continue;
        await db.update(techniciansTable)
          .set({ phone: seedRow.phone ?? undefined, website: seedRow.website ?? undefined })
          .where(eq(techniciansTable.id, row.id));
      }
      console.log(`[seed] Patch done.`);
    }
  }

export async function seedAutomotiveRepair(): Promise<void> {
  const result = await db.execute<{ count: string }>(
    sql`SELECT COUNT(*)::text AS count FROM technicians WHERE specialty = 'Automotive Repair'`
  );
  const count = parseInt(result.rows[0]?.count ?? "0", 10);
  if (count >= 100) return;

  console.log(`[seed] Automotive Repair has ${count} entries — seeding from automotive-repair-seed.json...`);

  const seedPath = join(
    typeof __dirname !== "undefined" ? __dirname : dirname(fileURLToPath(import.meta.url)),
    "automotive-repair-seed.json"
  );

  type SeedRow = {
    fullName: string; specialty: string; serviceArea: string; bio: string;
    hourlyRate: string | number; latitude: number | null; longitude: number | null;
    googlePlaceId: string; avatarUrl: string | null; phone: string | null; website: string | null;
  };

  let allRows: SeedRow[];
  try {
    allRows = JSON.parse(readFileSync(seedPath, "utf-8")) as SeedRow[];
  } catch (e) {
    console.error("[seed] Could not load automotive-repair-seed.json:", e);
    return;
  }

  let inserted = 0;
  for (let i = 0; i < allRows.length; i += 100) {
    const chunk = allRows.slice(i, i + 100);
    const res = await db.insert(techniciansTable).values(
      chunk.map(r => ({
        fullName: r.fullName,
        avatarUrl: r.avatarUrl ?? undefined,
        specialty: r.specialty ?? undefined,
        specialties: r.specialty ? [r.specialty] : undefined,
        serviceArea: r.serviceArea ?? undefined,
        bio: r.bio ?? undefined,
        hourlyRate: r.hourlyRate != null ? String(r.hourlyRate) : undefined,
        googlePlaceId: r.googlePlaceId ?? undefined,
        phone: r.phone ?? undefined,
        website: r.website ?? undefined,
        latitude: r.latitude ?? undefined,
        longitude: r.longitude ?? undefined,
        claimed: false,
        claimRequestPending: false,
      }))
    ).onConflictDoNothing();
    inserted += res.rowCount ?? 0;
  }

  console.log(`[seed] Inserted ${inserted} Automotive Repair profiles.`);
}

export async function seedAllTechnicians(): Promise<void> {
  const result = await db.execute<{ count: string }>(
    sql`SELECT COUNT(*)::text AS count FROM technicians`
  );
  const count = parseInt(result.rows[0]?.count ?? "0", 10);
  if (count >= 9000) return;

  console.log(`[seed] Production DB has ${count} technicians — seeding full dataset...`);

  const seedPath = join(
    typeof __dirname !== "undefined" ? __dirname : dirname(fileURLToPath(import.meta.url)),
    "technicians-seed.json"
  );

  type SeedRow = {
    fullName: string; specialty: string; serviceArea: string; bio: string;
    hourlyRate: number; latitude: number | null; longitude: number | null;
    googlePlaceId: string; avatarUrl: string | null; phone: string | null; website: string | null;
  };

  let allRows: SeedRow[];
  try {
    allRows = JSON.parse(readFileSync(seedPath, "utf-8")) as SeedRow[];
  } catch (e) {
    console.error("[seed] Could not load technicians-seed.json:", e);
    return;
  }

  let inserted = 0;
  for (let i = 0; i < allRows.length; i += 100) {
    const chunk = allRows.slice(i, i + 100);
    const res = await db.insert(techniciansTable).values(
      chunk.map(r => ({
        fullName: r.fullName,
        avatarUrl: r.avatarUrl ?? undefined,
        specialty: r.specialty ?? undefined,
        specialties: r.specialty ? [r.specialty] : undefined,
        serviceArea: r.serviceArea ?? undefined,
        bio: r.bio ?? undefined,
        hourlyRate: r.hourlyRate != null ? String(r.hourlyRate) : undefined,
        googlePlaceId: r.googlePlaceId ?? undefined,
        phone: r.phone ?? undefined,
        website: r.website ?? undefined,
        latitude: r.latitude ?? undefined,
        longitude: r.longitude ?? undefined,
        claimed: false,
        claimRequestPending: false,
      }))
    ).onConflictDoNothing();
    inserted += res.rowCount ?? 0;
  }

  console.log(`[seed] Inserted ${inserted} new technician profiles. Total now: ${count + inserted}.`);
}

export async function removeDemoTechnicians(): Promise<void> {
  const result = await db.execute<{ count: string }>(
    sql`DELETE FROM technicians WHERE google_place_id IS NULL RETURNING id`
  );
  if (result.rowCount && result.rowCount > 0) {
    console.log(`[seed] Removed ${result.rowCount} demo technician(s).`);
  }
}

export async function cleanupOrphanedTestData(): Promise<void> {
  // Remove thank_messages referencing technicians that no longer exist (demo techs)
  const tm = await db.execute<{ count: string }>(
    sql`DELETE FROM thank_messages
        WHERE technician_id NOT IN (SELECT id FROM technicians)
        RETURNING id`
  );
  if (tm.rowCount && tm.rowCount > 0) {
    console.log(`[seed] Removed ${tm.rowCount} orphaned thank message(s).`);
  }

  // Remove jobs referencing technicians that no longer exist
  const jb = await db.execute<{ count: string }>(
    sql`DELETE FROM jobs
        WHERE technician_id NOT IN (SELECT id FROM technicians)
        RETURNING id`
  );
  if (jb.rowCount && jb.rowCount > 0) {
    console.log(`[seed] Removed ${jb.rowCount} orphaned job(s).`);
  }

  // Clear any remaining test point data
  await db.execute(sql`DELETE FROM point_transactions`);
  await db.execute(sql`DELETE FROM points`);
  await db.execute(sql`DELETE FROM guest_tips`);

  // Reset technician counters to match real thank_messages
  await db.execute(
    sql`UPDATE technicians t
        SET total_thanks = COALESCE((
              SELECT COUNT(*) FROM thank_messages tm WHERE tm.technician_id = t.id
            ), 0),
            total_earned  = COALESCE((
              SELECT SUM(tip_amount) FROM thank_messages tm WHERE tm.technician_id = t.id
            ), 0)`
  );
}
  